def main():
    if len(sys.argv) < 2:
        print("Usage: python todo.py [add|list|remove] [args]")
        return

    command = sys.argv[1]

    if command == "add":
        content = sys.argv[2]
        todos = load_todos()
        todos.append(content)
        save_todos(todos)

    elif command == "list":
        todos = load_todos()
        for i, todo in enumerate(todos, start=1):
            print(f"{i}: {todo}")

    elif command == "remove":
        todo_id = int(sys.argv[2])
        todos = load_todos()
        if 1 <= todo_id <= len(todos):
            todos.pop(todo_id - 1)
            save_todos(todos)

